# ============================================================================ #
# L-BFGS Periodic Orbit Search — Lorenz System
# PLOTTING SCRIPT  (comprehensive)
#
# Reads the CSV files generated by `generate_data.jl` and produces the
# following figures:
#
#   Fig  1  – Convergence curves, fixed (T, N), varying m          (5×5 grid)
#   Fig  2  – Convergence curves, fixed (T, m), varying N          (5×6 grid)
#   Fig  3  – Convergence curves, fixed T/N ratio, varying m
#   Fig  4  – Convergence curves, fixed m/N ratio, varying T
#   Fig  5  – Heatmap: final ‖F‖ on (N, m) grid, one per T
#   Fig  6  – Heatmap: iterations to convergence on (N, m) grid
#   Fig  7  – Heatmap: wall-clock time on (N, m) grid
#   Fig  8  – Step-length λ vs iteration (selected cases)
#   Fig  9  – Phase portrait: ‖∇φ‖ vs ‖F‖
#   Fig 10  – Normalised convergence rate: ‖Fₖ‖ / ‖F₀‖
#   Fig 11  – Best final ‖F‖ vs T, per (N, m)
#   Fig 12  – Minimum N to converge vs T, per m
#
# Usage:  julia plot_results.jl
# ============================================================================ #

using Printf,
      DelimitedFiles,
      LinearAlgebra

using PyPlot

# ---------------------------------------------------------------------------- #
# 0.  Parameters (must match generate_data.jl)
# ---------------------------------------------------------------------------- #
const T_targets = [5.0, 10.0, 20.0, 40.0, 80.0]   # orbit periods
const Ms        = [1, 2, 5, 10, 20, 40]            # L-BFGS memory
const Ns        = [1, 2, 5, 10, 20]                # shooting segments
const e_tol     = 1e-8                              # convergence tolerance

const base_dir  = joinpath(@__DIR__, "..", "output", "l2_infinity_norm")
const plot_dir  = joinpath(@__DIR__, "..", "plots", "Plots_new_norm")
mkpath(plot_dir)

# ---------------------------------------------------------------------------- #
# 1.  Data loading
# ---------------------------------------------------------------------------- #
"""
    load_all_data()

Returns a nested Dict:
    data[T][N][m] = (iter, e_norm, grad_norm, lambda)
where each field is a Vector{Float64} (iter is Vector{Int}).
The last row of each CSV contains the final recomputed residual with
NaN entries for grad_norm and lambda.
"""
function load_all_data()
    data = Dict{Float64, Dict{Int, Dict{Int, NamedTuple}}}()

    for T in T_targets
        T_label = @sprintf("T%02d", round(Int, T))
        T_data  = Dict{Int, Dict{Int, NamedTuple}}()

        for N in Ns, m in Ms
            fname = @sprintf("N%02d_m%02d.csv", N, m)
            fpath = joinpath(base_dir, T_label, "data", fname)

            if !isfile(fpath)
                @warn "Missing file: $fpath"
                continue
            end

            # Read CSV, skip header row
            raw = readdlm(fpath, ',', skipstart=1)

            iter      = Vector{Int}(raw[:, 1])
            e_norm    = Vector{Float64}(raw[:, 2])
            grad_norm = Vector{Float64}(raw[:, 3])
            lambda    = Vector{Float64}(raw[:, 4])

            T_data[N] = get!(T_data, N, Dict{Int, NamedTuple}())
            T_data[N][m] = (iter=iter, e_norm=e_norm,
                            grad_norm=grad_norm, lambda=lambda)
        end

        data[T] = T_data
    end

    return data
end

println("Loading data ...")
const data = load_all_data()
println("Done.\n")

# ---------------------------------------------------------------------------- #
# 2.  Summary extraction helpers
# ---------------------------------------------------------------------------- #
"Check if a run converged: final ‖F‖ < tol."
converged(T, N, m) = data[T][N][m].e_norm[end] < e_tol

"Final residual norm."
final_normF(T, N, m) = data[T][N][m].e_norm[end]

"Number of L-BFGS iterations (excluding final recomputation row)."
n_iterations(T, N, m) = length(data[T][N][m].iter) - 1

"Extract elapsed time from the run log (in seconds).  Returns NaN if unavailable."
function elapsed_time(T, N, m)
    T_label = @sprintf("T%02d", round(Int, T))
    log_path = joinpath(base_dir, T_label, "run_log_$(T_label).txt")
    if !isfile(log_path)
        return NaN
    end
    pattern = @sprintf "N=%d, m=%d" N m
    for line in eachline(log_path)
        if startswith(line, "  " * pattern)
            # Parse "... 123.4 s" at end of line
            m_time = match(r"([\d.]+)\s*s\s*$", line)
            if m_time !== nothing
                return parse(Float64, m_time.captures[1])
            end
        end
    end
    return NaN
end

# ---------------------------------------------------------------------------- #
# 3.  Plotting style setup
# ---------------------------------------------------------------------------- #
rcParams = PyPlot.PyDict(PyPlot.matplotlib."rcParams")
rcParams["font.size"]         = 10
rcParams["axes.titlesize"]    = 10
rcParams["axes.labelsize"]    = 9
rcParams["legend.fontsize"]   = 7
rcParams["figure.dpi"]        = 150

# Colour maps for m and N curves
colors_m = Dict(zip(Ms, [plt.cm.viridis(i/(length(Ms)-1)) for i in 0:length(Ms)-1]))
colors_N = Dict(zip(Ns, [plt.cm.plasma(i/(length(Ns)-1)) for i in 0:length(Ns)-1]))
colors_T = Dict(zip(T_targets, [plt.cm.inferno(i/(length(T_targets)-1)) for i in 0:length(T_targets)-1]))

markers_N = Dict(zip(Ns, [:o, :s, :D, :^, :v]))
markers_m = Dict(zip(Ms, [:o, :s, :D, :^, :v, :p]))

# ---------------------------------------------------------------------------- #
# Helper: save figure in both PDF and PNG
# ---------------------------------------------------------------------------- #
function savefigs(name::String)
    plt.gcf().savefig(joinpath(plot_dir, "$name.pdf"),
                      dpi=150, bbox_inches="tight")
    plt.gcf().savefig(joinpath(plot_dir, "$name.png"),
                      dpi=150, bbox_inches="tight")
    println("  Saved: $name.pdf / .png")
end

# ---------------------------------------------------------------------------- #
# Helper: semilogy with safe floor at 1e-30 for log scale
# ---------------------------------------------------------------------------- #
safe_log(v) = max.(v, 1e-30)

# ============================================================================ #
# FIGURE 1  —  Convergence curves: fixed (T, N), varying m
#              One subplot per (T, N) combination  →  5×5 grid
# ============================================================================ #
function plot_fig1_fixed_TN_varying_m()
    println("Figure 1: Convergence per (T, N), varying m ...")

    fig, axes = plt.subplots(length(T_targets), length(Ns),
                              figsize=(3.2 * length(Ns), 2.8 * length(T_targets)),
                              sharex=true, sharey=true)
    fig.suptitle("L-BFGS Convergence — fixed (T, N), varying m",
                 fontsize=14, fontweight="bold")

    for (i, T) in enumerate(T_targets)
        for (j, N) in enumerate(Ns)
            ax = axes[i, j]
            for m in Ms
                d   = data[T][N][m]
                nit = length(d.iter) - 1
                cv  = d.e_norm[end] < e_tol ? "✓" : "✗"
                lbl = "m=$m [$nit it, $cv]"
                ax.semilogy(d.iter, safe_log.(d.e_norm), "-",
                            color=colors_m[m], linewidth=0.8, alpha=0.85, label=lbl)
            end
            ax.set_title("T=$(round(Int,T)), N=$N", fontsize=9)
            ax.legend(loc="upper right", ncol=2, fontsize=5)
            ax.grid(true, alpha=0.25)
            if i == length(T_targets); ax.set_xlabel("Iteration"); end
            if j == 1;               ax.set_ylabel("‖F(z)‖");     end
        end
    end

    fig.tight_layout()
    savefigs("fig01_fixed_TN_varying_m")
    plt.close(fig)
end

