# ============================================================================ #
# FIGURE 3  —  Convergence curves: fixed T/N ratio, varying m
# ============================================================================ #
function plot_fig3_fixed_TNratio_varying_m()
    println("Figure 3: Convergence for fixed T/N ratio, varying m ...")

    # Build T/N groups
    tn_groups = Dict{Float64, Vector{Tuple{Float64,Int}}}()
    for T in T_targets, N in Ns
        ratio = T / N
        vals  = get!(tn_groups, ratio, Tuple{Float64,Int}[])
        push!(vals, (T, N))
    end
    # Keep only groups with ≥ 2 members
    tn_groups = filter(p -> length(p.second) >= 2, tn_groups)
    # Sort by ratio
    ratios = sort(collect(keys(tn_groups)))

    ng = length(ratios)
    ncols = min(3, ng)
    nrows = ceil(Int, ng / ncols)

    fig, axes = plt.subplots(nrows, ncols,
                              figsize=(5 * ncols, 4 * nrows),
                              sharex=true, sharey=true)
    axes = axes isa Array ? vec(axes) : [axes]

    # Synthetic legend handles (one per m value), reused in every subplot
    handles_m = [plt.Line2D([0], [0], color=colors_m[m], linewidth=2,
                            label="m = $m") for m in Ms]

    for (idx, ratio) in enumerate(ratios)
        ax = axes[idx]
        for m in Ms
            # Collect all (T,N) with this ratio, plot their convergence curves.
            # Use same colour for same m.
            for (pi, (T, N)) in enumerate(tn_groups[ratio])
                d   = data[T][N][m]
                ax.semilogy(d.iter, safe_log.(d.e_norm), "-",
                            color=colors_m[m], linewidth=0.9, alpha=0.8)
            end
        end
        # Build a compact description of which (T,N) pairs are in this group
        pair_strs = ["T=$(round(Int,T)),N=$N" for (T,N) in tn_groups[ratio]]
        desc = "Pairs: " * join(pair_strs, ",  ")
        ax.set_title("T/N = $(round(ratio, digits=1))   [$desc]", fontsize=8)
        ax.legend(handles=handles_m, loc="upper right", ncol=2, fontsize=5)
        ax.set_xlabel("Iteration")
        ax.set_ylabel("‖F(z)‖")
        ax.grid(true, alpha=0.25)
    end

    # Hide unused axes
    for idx in (ng + 1):length(axes)
        axes[idx].set_visible(false)
    end

    fig.suptitle("L-BFGS Convergence — fixed T/N ratio, varying m",
                 fontsize=14, fontweight="bold")
    fig.tight_layout()
    savefigs("fig03_fixed_TNratio_varying_m")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 4  —  Convergence curves: fixed m/N ratio, varying T
# ============================================================================ #
function plot_fig4_fixed_mNratio_varying_T()
    println("Figure 4: Convergence for fixed m/N ratio, varying T ...")

    # Build m/N groups
    mn_groups = Dict{Float64, Vector{Tuple{Int,Int}}}()
    for m in Ms, N in Ns
        ratio = m / N
        vals  = get!(mn_groups, ratio, Tuple{Int,Int}[])
        push!(vals, (m, N))
    end
    mn_groups = filter(p -> length(p.second) >= 2, mn_groups)
    ratios_mn = sort(collect(keys(mn_groups)))

    ng = length(ratios_mn)
    ncols = min(3, ng)
    nrows = ceil(Int, ng / ncols)

    fig, axes = plt.subplots(nrows, ncols,
                              figsize=(5 * ncols, 4 * nrows),
                              sharex=true, sharey=true)
    axes = axes isa Array ? vec(axes) : [axes]

    # Synthetic legend handles (one per T value), reused in every subplot
    handles_T = [plt.Line2D([0], [0], color=colors_T[T], linewidth=2,
                            label="T = $(round(Int,T))") for T in T_targets]

    for (idx, ratio) in enumerate(ratios_mn)
        ax = axes[idx]
        for (pi, (m, N)) in enumerate(mn_groups[ratio])
            for T in T_targets
                d = data[T][N][m]
                ax.semilogy(d.iter, safe_log.(d.e_norm), "-",
                            color=colors_T[T], linewidth=0.9, alpha=0.8)
            end
        end
        pair_strs = ["m=$m,N=$N" for (m,N) in mn_groups[ratio]]
        desc = "Pairs: " * join(pair_strs, ",  ")
        ax.set_title("m/N = $(round(ratio, digits=2))   [$desc]", fontsize=8)
        ax.legend(handles=handles_T, loc="upper right", ncol=2, fontsize=5)
        ax.set_xlabel("Iteration")
        ax.set_ylabel("‖F(z)‖")
        ax.grid(true, alpha=0.25)
    end

    for idx in (ng + 1):length(axes)
        axes[idx].set_visible(false)
    end

    fig.suptitle("L-BFGS Convergence — fixed m/N ratio, varying T",
                 fontsize=14, fontweight="bold")
    fig.tight_layout()
    savefigs("fig04_fixed_mNratio_varying_T")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 5  —  Heatmap: final ‖F‖ on (N, m) grid, one per T
# ============================================================================ #
function plot_fig5_final_normF_heatmap()
    println("Figure 5: Final ‖F‖ heatmaps ...")

    fig, axes = plt.subplots(2, 3, figsize=(18, 10))
    axes = vec(axes)
    fig.suptitle("Final ‖F(z)‖ — L-BFGS, Lorenz System",
                 fontsize=15, fontweight="bold")

    # Build data matrices
    for (idx, T) in enumerate(T_targets)
        ax = axes[idx]
        mat = zeros(length(Ns), length(Ms))
        annot = fill("", length(Ns), length(Ms))
        for (i, N) in enumerate(Ns)
            for (j, m) in enumerate(Ms)
                fn = final_normF(T, N, m)
                mat[i, j] = fn < e_tol ? e_tol : fn  # floor converged at tol
                cv = converged(T, N, m) ? "✓" : "✗"
                annot[i, j] = cv
            end
        end

        im = ax.pcolormesh(Ms, Ns, log10.(max.(mat, 1e-30)),
                           cmap="viridis_r", shading="auto",
                           vmin=-12, vmax=0)
        # Annotate with ✓/✗
        for (i, N) in enumerate(Ns)
            for (j, m) in enumerate(Ms)
                color = converged(T, N, m) ? "white" : "black"
                ax.text(m, N, annot[i, j], ha="center", va="center",
                        fontsize=11, fontweight="bold", color=color)
            end
        end
        ax.set_title("T = $(round(Int, T))", fontsize=12)
        ax.set_xlabel("L-BFGS memory m")
        ax.set_ylabel("Segments N")
        ax.set_xticks(Ms)
        ax.set_yticks(Ns)
        plt.colorbar(im, ax=ax, label="log₁₀ ‖F(z)‖")
    end

    # Hide extra subplot (5 T-values → 2×3 grid, hide 6th)
    axes[6].set_visible(false)

    fig.tight_layout(rect=[0, 0, 1, 0.95])
    savefigs("fig05_final_normF_heatmap")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 6  —  Heatmap: iterations to converge
# ============================================================================ #
function plot_fig6_iterations_heatmap()
    println("Figure 6: Iterations-to-converge heatmaps ...")

    fig, axes = plt.subplots(2, 3, figsize=(18, 10))
    axes = vec(axes)
    fig.suptitle("L-BFGS Iterations — Lorenz System  (× = did not converge)",
                 fontsize=15, fontweight="bold")

    for (idx, T) in enumerate(T_targets)
        ax = axes[idx]
        mat = zeros(length(Ns), length(Ms))
        for (i, N) in enumerate(Ns)
            for (j, m) in enumerate(Ms)
                nit  = n_iterations(T, N, m)
                conv = converged(T, N, m)
                # For non-converged, display 0 → masked
                mat[i, j] = conv ? nit : 0
            end
        end

        # Mask non-converged cells
        masked = copy(mat)
        masked[masked .== 0] .= NaN

        im = ax.pcolormesh(Ms, Ns, masked,
                           cmap="plasma", shading="auto")
        # Annotate
        for (i, N) in enumerate(Ns)
            for (j, m) in enumerate(Ms)
                conv = converged(T, N, m)
                nit  = n_iterations(T, N, m)
                if conv
                    ax.text(m, N, "$nit", ha="center", va="center",
                            fontsize=8, color="white", fontweight="bold")
                else
                    ax.text(m, N, "✗", ha="center", va="center",
                            fontsize=13, color="black", fontweight="bold")
                end
            end
        end
        ax.set_title("T = $(round(Int, T))", fontsize=12)
        ax.set_xlabel("L-BFGS memory m")
        ax.set_ylabel("Segments N")
        ax.set_xticks(Ms)
        ax.set_yticks(Ns)
        plt.colorbar(im, ax=ax, label="Iterations")
    end

    axes[6].set_visible(false)
    fig.tight_layout(rect=[0, 0, 1, 0.95])
    savefigs("fig06_iterations_heatmap")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 7  —  Heatmap: wall-clock time
# ============================================================================ #
function plot_fig7_time_heatmap()
    println("Figure 7: Wall-clock time heatmaps ...")

    fig, axes = plt.subplots(2, 3, figsize=(18, 10))
    axes = vec(axes)
    fig.suptitle("Wall-Clock Time [s] — L-BFGS, Lorenz System",
                 fontsize=15, fontweight="bold")

    for (idx, T) in enumerate(T_targets)
        ax = axes[idx]
        mat = zeros(length(Ns), length(Ms))
        for (i, N) in enumerate(Ns)
            for (j, m) in enumerate(Ms)
                mat[i, j] = elapsed_time(T, N, m)
            end
        end

        im = ax.pcolormesh(Ms, Ns, log10.(max.(mat, 0.01)),
                           cmap="inferno_r", shading="auto")
        for (i, N) in enumerate(Ns)
            for (j, m) in enumerate(Ms)
                t = mat[i, j]
                cv = converged(T, N, m)
                color = t > 50 ? "white" : "black"
                if isfinite(t)
                    ax.text(m, N, @sprintf("%.1f", t), ha="center", va="center",
                            fontsize=7, color=color)
                end
            end
        end
        ax.set_title("T = $(round(Int, T))", fontsize=12)
        ax.set_xlabel("L-BFGS memory m")
        ax.set_ylabel("Segments N")
        ax.set_xticks(Ms)
        ax.set_yticks(Ns)
        plt.colorbar(im, ax=ax, label="log₁₀ time [s]")
    end

    axes[6].set_visible(false)
    fig.tight_layout(rect=[0, 0, 1, 0.95])
    savefigs("fig07_time_heatmap")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 8  —  Step-length λ vs iteration (selected converged cases)
# ============================================================================ #
function plot_fig8_lambda_diagnostics()
    println("Figure 8: Lambda (step length) diagnostics ...")

    # Pick representative converged cases: T=20, all N, best & worst m
    T = 20.0

    fig, axes = plt.subplots(length(Ns), 1, figsize=(12, 3 * length(Ns)),
                              sharex=true)
    fig.suptitle("Step Length λ vs Iteration — Lorenz T=$(round(Int,T))",
                 fontsize=14, fontweight="bold")

    for (idx, N) in enumerate(Ns)
        ax = axes[idx]
        for m in Ms
            d = data[T][N][m]
            # Remove last row (NaN lambda) and iteration 0 (λ=0)
            iters = d.iter[1:end-1]   # all except last
            lams  = d.lambda[1:end-1]
            # Only plot non-NaN (skip failed runs that have empty history)
            if length(iters) > 1
                cv = converged(T, N, m)
                ls = cv ? "-" : ":"
                ax.plot(iters, lams, ls, color=colors_m[m], linewidth=0.8,
                        alpha=0.7, label="m=$m")
            end
        end
        ax.set_ylabel("λ  (step length)")
        ax.set_title("N = $N")
        ax.axhline(1.0, color="gray", linestyle="--", linewidth=0.5, alpha=0.5)
        ax.set_ylim(-0.05, 1.3)
        ax.legend(loc="upper right", ncol=3, fontsize=7)
        ax.grid(true, alpha=0.25)
    end
    axes[end].set_xlabel("Iteration")

    fig.tight_layout(rect=[0, 0, 1, 0.96])
    savefigs("fig08_lambda_diagnostics")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 9  —  Phase portrait: ‖∇φ‖ vs ‖F‖  (log-log)
# ============================================================================ #
function plot_fig9_gradient_vs_residual()
    println("Figure 9: Phase portrait ‖∇φ‖ vs ‖F‖ ...")

    T = 20.0
    fig, axes = plt.subplots(length(Ns), 1, figsize=(12, 3 * length(Ns)),
                              sharex=true)
    fig.suptitle("Phase Portrait: ‖∇φ‖ vs ‖F(z)‖ — Lorenz T=$(round(Int,T))",
                 fontsize=14, fontweight="bold")

    for (idx, N) in enumerate(Ns)
        ax = axes[idx]
        for m in Ms
            d   = data[T][N][m]
            # Use only rows with finite grad_norm (last row has NaN)
            valid = isfinite.(d.grad_norm)
            fn   = d.e_norm[valid]
            gn   = d.grad_norm[valid]
            cv   = converged(T, N, m)
            if length(fn) > 1
                ls = cv ? "-" : ":"
                ax.loglog(fn, gn, ls, color=colors_m[m], linewidth=0.8,
                          alpha=0.7, label="m=$m")
            end
        end
        ax.set_xlabel("‖F(z)‖")
        ax.set_ylabel("‖∇φ‖")
        ax.set_title("N = $N")
        ax.legend(loc="lower right", ncol=3, fontsize=7)
        ax.grid(true, alpha=0.25)
    end

    fig.tight_layout(rect=[0, 0, 1, 0.96])
    savefigs("fig09_gradient_vs_residual")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 10 —  Normalised convergence rate: ‖Fₖ‖ / ‖F₀‖
# ============================================================================ #
function plot_fig10_normalised_convergence()
    println("Figure 10: Normalised convergence rate ...")

    T = 20.0
    fig, axes = plt.subplots(length(Ns), 1, figsize=(12, 3 * length(Ns)),
                              sharex=true)
    fig.suptitle("Normalised Residual ‖Fₖ‖/‖F₀‖ — Lorenz T=$(round(Int,T))",
                 fontsize=14, fontweight="bold")

    for (idx, N) in enumerate(Ns)
        ax = axes[idx]
        for m in Ms
            d   = data[T][N][m]
            f0  = d.e_norm[1]
            fn  = d.e_norm / f0
            cv  = converged(T, N, m)
            ls  = cv ? "-" : ":"
            ax.semilogy(d.iter, safe_log.(fn), ls, color=colors_m[m],
                        linewidth=0.8, alpha=0.7, label="m=$m")
        end
        ax.axhline(e_tol / maximum([final_normF(T, N, m) for m in Ms]),
                   color="gray", linestyle="--", linewidth=0.5, alpha=0.4)
        ax.set_ylabel("‖Fₖ‖ / ‖F₀‖")
        ax.set_title("N = $N")
        ax.legend(loc="upper right", ncol=3, fontsize=7)
        ax.grid(true, alpha=0.25)
    end
    axes[end].set_xlabel("Iteration")

    fig.tight_layout(rect=[0, 0, 1, 0.96])
    savefigs("fig10_normalised_convergence")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 11 —  Best final ‖F‖ vs T, per (N, m) pair
# ============================================================================ #
function plot_fig11_best_final_vs_T()
    println("Figure 11: Best final ‖F‖ vs T ...")

    fig, axes = plt.subplots(length(Ns), 1, figsize=(10, 3.2 * length(Ns)),
                              sharex=true)
    fig.suptitle("Final ‖F(z)‖ vs Orbit Period T",
                 fontsize=14, fontweight="bold")

    for (idx, N) in enumerate(Ns)
        ax = axes[idx]
        for m in Ms
            finals = [final_normF(T, N, m) for T in T_targets]
            cv_all = [converged(T, N, m) for T in T_targets]
            marker = markers_m[m]
            ls = "-" * string(marker)
            ax.semilogy(T_targets, safe_log.(finals), ls,
                        color=colors_m[m], markersize=7, linewidth=1.2,
                        label="m=$m")
            # Mark converged with filled, non-converged with open
            for (ti, T) in enumerate(T_targets)
                if cv_all[ti]
                    ax.plot([T], [max(finals[ti], 1e-12)], "o",
                            color=colors_m[m], markersize=9)
                else
                    ax.plot([T], [max(finals[ti], 1e-12)], "o",
                            color=colors_m[m], markersize=9, markerfacecolor="none")
                end
            end
        end
        ax.axhline(e_tol, color="gray", linestyle="--", linewidth=0.8, alpha=0.5,
                   label="tol = 1e-8")
        ax.set_ylabel("Final ‖F(z)‖")
        ax.set_title("N = $N segments")
        ax.legend(loc="lower right", ncol=4, fontsize=7)
        ax.grid(true, alpha=0.25)
        ax.set_xticks(T_targets)
    end
    axes[end].set_xlabel("Orbit period T")

    fig.tight_layout(rect=[0, 0, 1, 0.97])
    savefigs("fig11_best_final_vs_T")
    plt.close(fig)
end

# ============================================================================ #
# FIGURE 12 —  Minimum N to converge vs T, per m
# ============================================================================ #
function plot_fig12_minN_vs_T()
    println("Figure 12: Minimum N to converge vs T ...")

    fig, ax = plt.subplots(figsize=(10, 6))
    fig.suptitle("Minimum Shooting Segments N for Convergence  (‖F‖ < 1e-8)",
                 fontsize=13, fontweight="bold")

    for m in Ms
        min_Ns = Float64[]
        for T in T_targets
            # Find the smallest N such that converged(T, N, m)
            converged_Ns = [N for N in Ns if converged(T, N, m)]
            if isempty(converged_Ns)
                push!(min_Ns, NaN)
            else
                push!(min_Ns, Float64(minimum(converged_Ns)))
            end
        end
        # Only plot if at least one T converged
        if any(isfinite.(min_Ns))
            marker = markers_m[m]
            ax.plot(T_targets, min_Ns, "-" * string(marker),
                    color=colors_m[m], markersize=9, linewidth=1.5,
                    label="m = $m")
        end
    end

    ax.set_xlabel("Orbit period T")
    ax.set_ylabel("Minimum N to converge")
    ax.set_yticks(Ns)
    ax.set_xticks(T_targets)
    ax.legend(loc="upper left", ncol=2, fontsize=9)
    ax.grid(true, alpha=0.3)
    ax.set_ylim(0.5, max(Ns...) + 1)

    fig.tight_layout()
    savefigs("fig12_min_N_vs_T")
    plt.close(fig)
end

# ============================================================================ #
# 4.  Generate all figures
# ============================================================================ #
function main()
    println("="^60)
    println("  Generating all plots ...")
    println("  Output directory:  $plot_dir")
    println("="^60)
    println()

    # List of (label, function) pairs
    figs = [
        ("Figure  1: fixed (T,N), varying m",          plot_fig1_fixed_TN_varying_m),
        ("Figure  2: fixed (T,m), varying N",          plot_fig2_fixed_Tm_varying_N),
        ("Figure  3: fixed T/N ratio, varying m",      plot_fig3_fixed_TNratio_varying_m),
        ("Figure  4: fixed m/N ratio, varying T",      plot_fig4_fixed_mNratio_varying_T),
        ("Figure  5: final ||F|| heatmaps",            plot_fig5_final_normF_heatmap),
        ("Figure  6: iterations heatmaps",             plot_fig6_iterations_heatmap),
        ("Figure  7: wall-clock time heatmaps",        plot_fig7_time_heatmap),
        ("Figure  8: lambda diagnostics",              plot_fig8_lambda_diagnostics),
        ("Figure  9: phase portrait grad vs residual", plot_fig9_gradient_vs_residual),
        ("Figure 10: normalised convergence rate",     plot_fig10_normalised_convergence),
        ("Figure 11: best final residual vs T",        plot_fig11_best_final_vs_T),
        ("Figure 12: min N to converge vs T",          plot_fig12_minN_vs_T),
    ]

    for (label, f) in figs
        try
            Base.invokelatest(f)
        catch err
            println("ERROR in $label: $err")
            println("  Continuing with next figure ...")
        end
    end

    println()
    println("All plots saved to  $plot_dir")
end

Base.invokelatest(main)
